  ('social-worker-moex-00362', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體領導技巧的運用，下列何者錯誤？', '["領導者不具權力來中止團體的重大衝突而須透過團體協商來決定", "將問題分解部分化使問題被切割成比較容易解決的部分，可增加成員對問題與自我行為的覺察", "摘述是指團體的會期中主要的觀點能被精確的提出", "澄清技巧是針對成員表達不清楚的內容，請成員說得更清楚"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "37b94c9d4983", "answer_pdf_sha1": "6fac52332858", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00363', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關評估團體成效的方式，何者正確？', '["團體成員自我觀察與陳述不適宜做為評估方式", "可安排評估性團體活動進行評估", "使用標準化測量工具評估成效時，於每次團體都需進行施測", "團體工作紀錄不適合做為評估團體工作成效的依據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "37b94c9d4983", "answer_pdf_sha1": "6fac52332858", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00364', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作中使用身體接觸的技術，下列敘述何者錯誤？', '["使用身體接觸的技術，包括歡迎成員、悲傷時的輕拍、練習活動中的身體接觸及團體結束時的 擁抱等", "運用身體接觸的技術時，應將領導者性別因素納入考量", "練習活動前，可事先與成員討論身體界線", "團體壓力不會影響成年成員接受身體接觸"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "37b94c9d4983", "answer_pdf_sha1": "6fac52332858", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00365', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體帶領的過程涉及兩難問題時，領導者有責任妥善處理的工作，下列何者錯誤？', '["熟知其隸屬機構的期待及規定", "詳實記錄並妥善保管團體成員的相關資料", "不得利用團體成員，避免私人情感的介入", "尊重及保密團體的互動關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "37b94c9d4983", "answer_pdf_sha1": "6fac52332858", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00366', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作實施倫理的敘述，下列何者正確？', '["團體工作者未能精進自己的團體工作專業能力，提供合適的團體工作服務，屬於專業品質議題， 不屬於倫理議題", "團體工作者不可同時具有該團體的研究者角色，以免違反專業倫理", "團體成員之間的互相保密，只能靠成員間互相的承諾與彼此的自我約束來維持，無法透過倫理 規範確保保密原則的落實", "團體的目標、進行時間及期程，屬於工作契約內涵，非倫理規範的範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "37b94c9d4983", "answer_pdf_sha1": "6fac52332858", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
