  ('social-worker-moex-00368', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區培力中心是臺灣自 2014 年以來開始的一項政策方案，關於社區培力中心的敘述，下列何者 錯誤？', '["為地方政府鼓勵社區發展協會設置的培力中心", "引進專業社工人力對有發展性的社區發展協會進行專業性的輔導", "對基層社區之社區工作專業化的推進，有一定程度的貢獻", "提供社區工作專業人員專業職務的培力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "37b94c9d4983", "answer_pdf_sha1": "6fac52332858", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
