  ('social-worker-moex-00370', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在Popple（1995）所提出的女性主義與社會工作模式中，社區工作者的主要角色與職責，包含下', '["行動者", "使能者", "促進者", "教育者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "37b94c9d4983", "answer_pdf_sha1": "6fac52332858", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
